32: // makeStore creates an aggregate config store from several config stores and
33: // unifies their descriptors
34: func makeStore(stores []model.ConfigStore, writer model.ConfigStore) (model.ConfigStore, error) {
35: 	union := collection.NewSchemasBuilder()
36: 	storeTypes := make(map[config.GroupVersionKind][]model.ConfigStore)
37: 	for _, store := range stores {
38: 		for _, s := range store.Schemas().All() {
39: 			if len(storeTypes[s.GroupVersionKind()]) == 0 {
40: 				if err := union.Add(s); err != nil {
41: 					return nil, err
42: 				}
43: 			}
44: 			storeTypes[s.GroupVersionKind()] = append(storeTypes[s.GroupVersionKind()], store)
45: 		}
46: 	}
47: 
48: 	schemas := union.Build()
49: 	if err := schemas.Validate(); err != nil {
50: 		return nil, err
51: 	}
52: 	result := &store{
53: 		schemas: schemas,
54: 		stores:  storeTypes,
55: 		writer:  writer,
56: 	}
57: 
58: 	return result, nil
59: }
60: 
61: // MakeWriteableCache creates an aggregate config store cache from several config store caches. An additional
62: // `writer` config store is passed, which may or may not be part of `caches`.
63: func MakeWriteableCache(caches []model.ConfigStoreController, writer model.ConfigStore) (model.ConfigStoreController, error) {
64: 	stores := make([]model.ConfigStore, 0, len(caches))
65: 	for _, cache := range caches {
66: 		stores = append(stores, cache)
67: 	}
68: 	store, err := makeStore(stores, writer)
69: 	if err != nil {
70: 		return nil, err
71: 	}
72: 	return &storeCache{
73: 		ConfigStore: store,
74: 		caches:      caches,
75: 	}, nil
76: }
77: 
78: // MakeCache creates an aggregate config store cache from several config store
79: // caches.
80: func MakeCache(caches []model.ConfigStoreController) (model.ConfigStoreController, error) {
81: 	return MakeWriteableCache(caches, nil)
82: }
