874: // initRegistryEventHandlers sets up event handlers for config and service updates
875: func (s *Server) initRegistryEventHandlers() {
876: 	log.Info("initializing registry event handlers")
877: 	// Flush cached discovery responses whenever services configuration change.
878: 	serviceHandler := func(prev, curr *model.Service, event model.Event) {
879: 		pushReq := &model.PushRequest{
880: 			Full:           true,
881: 			ConfigsUpdated: sets.New(model.ConfigKey{Kind: kind.ServiceEntry, Name: string(curr.Hostname), Namespace: curr.Attributes.Namespace}),
882: 			Reason:         model.NewReasonStats(model.ServiceUpdate),
883: 		}
884: 		s.XDSServer.ConfigUpdate(pushReq)
885: 	}
886: 	s.ServiceController().AppendServiceHandler(serviceHandler)
887: 
888: 	if s.configController != nil {
889: 		configHandler := func(prev config.Config, curr config.Config, event model.Event) {
890: 			log.Debugf("Handle event %s for configuration %s", event, curr.Key())
891: 			// For update events, trigger push only if spec has changed.
892: 			if event == model.EventUpdate && !needsPush(prev, curr) {
893: 				log.Debugf("skipping push for %s as spec has not changed", prev.Key())
894: 				return
895: 			}
896: 			pushReq := &model.PushRequest{
897: 				Full:           true,
898: 				ConfigsUpdated: sets.New(model.ConfigKey{Kind: kind.MustFromGVK(curr.GroupVersionKind), Name: curr.Name, Namespace: curr.Namespace}),
899: 				Reason:         model.NewReasonStats(model.ConfigUpdate),
900: 			}
901: 			s.XDSServer.ConfigUpdate(pushReq)
902: 		}
903: 		schemas := collections.Pilot.All()
904: 		if features.EnableGatewayAPI {
905: 			schemas = collections.PilotGatewayAPI().All()
906: 		}
907: 		for _, schema := range schemas {
908: 			// This resource type was handled in external/servicediscovery.go, no need to rehandle here.
909: 			if schema.GroupVersionKind() == gvk.ServiceEntry {
910: 				continue
911: 			}
912: 			if schema.GroupVersionKind() == gvk.WorkloadEntry {
913: 				continue
914: 			}
915: 			if schema.GroupVersionKind() == gvk.WorkloadGroup {
916: 				continue
917: 			}
918: 
919: 			s.configController.RegisterEventHandler(schema.GroupVersionKind(), configHandler)
920: 		}
921: 		if s.environment.GatewayAPIController != nil {
922: 			s.environment.GatewayAPIController.RegisterEventHandler(gvk.Namespace, func(config.Config, config.Config, model.Event) {
923: 				s.XDSServer.ConfigUpdate(&model.PushRequest{
924: 					Full:   true,
925: 					Reason: model.NewReasonStats(model.NamespaceUpdate),
926: 				})
927: 			})
928: 			s.environment.GatewayAPIController.RegisterEventHandler(gvk.Secret, func(_ config.Config, gw config.Config, _ model.Event) {
929: 				s.XDSServer.ConfigUpdate(&model.PushRequest{
930: 					Full: true,
931: 					ConfigsUpdated: map[model.ConfigKey]struct{}{
932: 						{
933: 							Kind:      kind.KubernetesGateway,
934: 							Name:      gw.Name,
935: 							Namespace: gw.Namespace,
936: 						}: {},
937: 					},
938: 					Reason: model.NewReasonStats(model.SecretTrigger),
939: 				})
