297: // ConfigUpdate implements ConfigUpdater interface, used to request pushes.
298: func (s *DiscoveryServer) ConfigUpdate(req *model.PushRequest) {
299: 	if features.EnableUnsafeAssertions {
300: 		if model.HasConfigsOfKind(req.ConfigsUpdated, kind.Service) {
301: 			panic("assertion failed kind.Service can not be set in ConfigKey")
302: 		}
303: 	}
304: 	if model.HasConfigsOfKind(req.ConfigsUpdated, kind.Address) {
305: 		// This is a bit like clearing EDS cache on EndpointShard update. Because Address
306: 		// types are fetched dynamically, they are not part of the same protections, so we need to clear
307: 		// the cache.
308: 		s.Cache.ClearAll()
309: 	}
310: 	inboundConfigUpdates.Increment()
311: 	s.InboundUpdates.Inc()
312: 	if req.Full && fullPushLog.DebugEnabled() {
313: 		configs := slices.Sort(slices.Map(req.ConfigsUpdated.UnsortedList(), model.ConfigKey.String))
314: 		reasons := maps.Keys(req.Reason)
315: 		fullPushLog.Debugf("full push triggered configs=%v reasons=%v", configs, reasons)
316: 	}
317: 	s.pushChannel <- req
318: }
