320: // Debouncing and push request happens in a separate thread, it uses locks
321: // and we want to avoid complications, ConfigUpdate may already hold other locks.
322: // handleUpdates processes events from pushChannel
323: // It ensures that at minimum minQuiet time has elapsed since the last event before processing it.
324: // It also ensures that at most maxDelay is elapsed between receiving an event and processing it.
325: func (s *DiscoveryServer) handleUpdates(stopCh <-chan struct{}) {
326: 	debounce(s.pushChannel, stopCh, s.DebounceOptions, s.Push, s.CommittedUpdates)
327: }
