329: // The debounce helper function is implemented to enable mocking
330: func debounce(ch chan *model.PushRequest, stopCh <-chan struct{}, opts DebounceOptions, pushFn func(req *model.PushRequest), updateSent *atomic.Int64) {
331: 	var timeChan <-chan time.Time
332: 	var startDebounce time.Time
333: 	var lastConfigUpdateTime time.Time
334: 
335: 	pushCounter := 0
336: 	debouncedEvents := 0
337: 
338: 	// Keeps track of the push requests. If updates are debounce they will be merged.
339: 	var req *model.PushRequest
340: 
341: 	free := true
342: 	freeCh := make(chan struct{}, 1)
343: 
344: 	push := func(req *model.PushRequest, debouncedEvents int, startDebounce time.Time) {
345: 		pushFn(req)
346: 		updateSent.Add(int64(debouncedEvents))
347: 		debounceTime.Record(time.Since(startDebounce).Seconds())
348: 		freeCh <- struct{}{}
349: 	}
350: 
351: 	pushWorker := func() {
352: 		eventDelay := time.Since(startDebounce)
353: 		quietTime := time.Since(lastConfigUpdateTime)
354: 		// it has been too long or quiet enough
355: 		if eventDelay >= opts.debounceMax || quietTime >= opts.DebounceAfter {
356: 			if req != nil {
357: 				pushCounter++
358: 				if req.ConfigsUpdated == nil {
359: 					log.Infof("Push debounce stable[%d] %d for reason %s: %v since last change, %v since last push, full=%v",
360: 						pushCounter, debouncedEvents, reasonsUpdated(req),
361: 						quietTime, eventDelay, req.Full)
362: 				} else {
363: 					log.Infof("Push debounce stable[%d] %d for config %s: %v since last change, %v since last push, full=%v",
364: 						pushCounter, debouncedEvents, configsUpdated(req),
365: 						quietTime, eventDelay, req.Full)
366: 				}
367: 				free = false
368: 				go push(req, debouncedEvents, startDebounce)
369: 				req = nil
370: 				debouncedEvents = 0
371: 			}
372: 		} else {
373: 			timeChan = time.After(opts.DebounceAfter - quietTime)
374: 		}
375: 	}
376: 
377: 	for {
378: 		select {
379: 		case <-freeCh:
380: 			free = true
381: 			pushWorker()
382: 		case r := <-ch:
383: 			// If reason is not set, record it as an unknown reason
384: 			if len(r.Reason) == 0 {
385: 				r.Reason = model.NewReasonStats(model.UnknownTrigger)
386: 			}
387: 			if !opts.enableEDSDebounce && !r.Full {
388: 				// trigger push now, just for EDS
389: 				go func(req *model.PushRequest) {
390: 					pushFn(req)
391: 					updateSent.Inc()
392: 				}(r)
393: 				continue
394: 			}
395: 
396: 			lastConfigUpdateTime = time.Now()
397: 			if debouncedEvents == 0 {
398: 				timeChan = time.After(opts.DebounceAfter)
399: 				startDebounce = lastConfigUpdateTime
400: 			}
